class Solution:
    def maxNumOfSubstrings(self, s):
        n = len(s)
        first = {}
        last = {}
        for i, c in enumerate(s):
            if c not in first:
                first[c] = i
            last[c] = i
        interval_at = {}
        for i in range(n):
            c = s[i]
            if first[c] != i:
                continue
            start, end = i, last[c]
            j = start
            valid = True
            while j <= end:
                c2 = s[j]
                if first[c2] < start:
                    valid = False
                    break
                if last[c2] > end:
                    end = last[c2]
                j += 1
            if valid:
                interval_at[start] = end
        best_count = [0] * (n + 1)
        best_len = [0] * (n + 1)
        take = [False] * (n + 1)
        take_end = [-1] * (n + 1)
        for i in range(n - 1, -1, -1):
            best_count[i] = best_count[i + 1]
            best_len[i] = best_len[i + 1]
            take[i] = False
            if i in interval_at:
                end = interval_at[i]
                c2 = best_count[end + 1] + 1
                l2 = best_len[end + 1] + (end - i + 1)
                if c2 > best_count[i] or (c2 == best_count[i] and l2 < best_len[i]):
                    best_count[i], best_len[i] = c2, l2
                    take[i] = True
                    take_end[i] = end
        res = []
        i = 0
        while i < n:
            if take[i]:
                res.append(s[i:take_end[i] + 1])
                i = take_end[i] + 1
            else:
                i += 1
        return res

