class Solution:
    def maxNumOfSubstrings(self, s: str):
        first = {}
        last = {}
        for i, c in enumerate(s):
            if c not in first:
                first[c] = i
            last[c] = i
        candidates = []
        n = len(s)
        for i in range(n):
            c = s[i]
            if first[c] != i:
                continue
            start, end = i, last[c]
            j = start
            valid = True
            while j <= end:
                c2 = s[j]
                if first[c2] < start:
                    valid = False
                    break
                if last[c2] > end:
                    end = last[c2]
                j += 1
            if valid:
                candidates.append((end, start))
        candidates.sort()
        res = []
        prev_end = -1
        for end, start in candidates:
            if start > prev_end:
                res.append(s[start:end + 1])
                prev_end = end
        return res

