var maxNumOfSubstrings = function(s) {
    const first = new Map();
    const last = new Map();
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (!first.has(c)) first.set(c, i);
        last.set(c, i);
    }
    const candidates = [];
    const n = s.length;
    for (let i = 0; i < n; i++) {
        const c = s[i];
        if (first.get(c) !== i) continue;
        let start = i, end = last.get(c);
        let j = start;
        let valid = true;
        while (j <= end) {
            const c2 = s[j];
            if (first.get(c2) < start) {
                valid = false;
                break;
            }
            if (last.get(c2) > end) end = last.get(c2);
            j++;
        }
        if (valid) candidates.push([end, start]);
    }
    candidates.sort((a, b) => (a[0] - b[0]) || (a[1] - b[1]));
    const res = [];
    let prevEnd = -1;
    for (const [end, start] of candidates) {
        if (start > prevEnd) {
            res.push(s.slice(start, end + 1));
            prevEnd = end;
        }
    }
    return res;
};
